let searchbox=document.querySelector("#pref"),messagebox=document.querySelector("#message"),suggestions=document.querySelector(".suggestions ul"),prefectures=["Consultanță digitală","Strategie marketing","Personal branding","Social Media","SEO","Campanii PPC / Ads","Design logo","Manual de brand","Servicii foto profesionale","Birotică personalizată","Cărți de vizită","Email personalizate","UI/UX","Copywriting","Website","Mobile (iOS / Android)","QA","Audit securitate"];function selectTwoRandomElements(e){const s=[];for(;s.length<2;){const t=Math.floor(Math.random()*e.length);s.includes(t)||s.push(t)}const t=s.map(s=>e[s]);return t[0]+", "+t[1]+", ..."}function search(e){term=e.toLowerCase();let s=[];for(i=0;i<prefectures.length;i++)prefectures[i].toLowerCase().indexOf(term)>-1&&s.push(prefectures[i]);return s}function searchHandler(e){str=e.target.value,res=search(str),1===res.length&&(searchbox.value=res[0],searchbox.blur(),messagebox.focus(),suggestions.classList.remove("has-suggestions")),showResults(res,str)}function showResults(e,s){if(suggestions.innerHTML="",e.length>1){for(i=0;i<e.length;i++){let s=e[i];suggestions.innerHTML+=`<li>${s}</li>`}suggestions.classList.add("has-suggestions")}}function useSuggestion(e){searchbox.value=e.target.innerText,searchbox.focus(),suggestions.innerHTML="",suggestions.classList.remove("has-suggestions")}function hideSuggestions(e){suggestions.classList.remove("has-suggestions")}searchbox.placeholder=selectTwoRandomElements(prefectures),searchbox.addEventListener("keyup",searchHandler),searchbox.addEventListener("blur",hideSuggestions),suggestions.addEventListener("click",useSuggestion),suggestions.addEventListener("click",searchHandler);